// Part Annotation & Info Panel (Now in Left Panel Side)
const PartProperties = () => {
  const { selectedPart, partAnnotations, setAnnotation, partConfigs, updatePartConfig, isExploded, toggleExploded } = useStore();

  // Logic to determine defaults if annotation doesn't exist yet
  const getDisplayName = (id: string) => {
      const preset = SHOE_PARTS.find(p => p.id === id);
      if (preset) return preset.name;
      // Fallback: beautify ID
      return id.replace(/[_-]/g, ' ').replace(/([A-Z])/g, ' $1').replace(/^./, str => str.toUpperCase()).trim();
  };

  const savedAnnotation = selectedPart ? partAnnotations[selectedPart] : null;
  const defaultTitle = selectedPart ? getDisplayName(selectedPart) : '';

  // Use saved title if exists, otherwise default. Use '' if user explicitly cleared it (saved but empty).
  const titleValue = savedAnnotation ? savedAnnotation.title : defaultTitle;
  const descValue = savedAnnotation ? savedAnnotation.description : '';
  const offsetValue = savedAnnotation?.offset || 60;

  const handleUpdate = (field: string, value: any) => {
     if (!selectedPart) return;
     setAnnotation(selectedPart, {
        title: titleValue,
        description: descValue,
        offset: offsetValue,
        [field]: value
     });
  };

  const currentConfig = selectedPart ? (partConfigs[selectedPart] || { explosionOffset: [0,0,0], meshScale: 1 }) : null;
  const [ex, ey, ez] = currentConfig?.explosionOffset || [0, 0, 0];
  const meshScale = currentConfig?.meshScale !== undefined ? currentConfig.meshScale : 1;

  const updateExplosion = (index: number, val: number) => {
    if (!selectedPart) return;
    const newOffset = [...(currentConfig?.explosionOffset || [0,0,0])] as [number, number, number];
    newOffset[index] = val;
    updatePartConfig(selectedPart, { explosionOffset: newOffset });
  };

  const updateScale = (val: number) => {
    if (!selectedPart) return;
    updatePartConfig(selectedPart, { meshScale: val });
  };

  if (!selectedPart) return null;

  return (
       <div className="flex flex-col h-full">
          <div className="p-3 border-b border-white/5 bg-white/5 backdrop-blur-xl flex items-center gap-2 shrink-0">
            <TypeIcon size={14} className="text-blue-400"/>
            <span className="text-xs font-bold uppercase tracking-wider text-zinc-400">Annotation & Transform</span>
          </div>
          <div className="p-3 flex flex-col gap-4 overflow-y-auto custom-scrollbar">
              <div className="flex flex-col gap-3">
                 <div>
                    <span className="text-[10px] font-medium text-zinc-400 block mb-1">Title</span>
                    <input 
                      type="text" 
                      value={titleValue} 
                      onChange={(e) => handleUpdate('title', e.target.value)}
                      placeholder="Part Name"
                      className="w-full bg-black/30 border border-white/10 rounded px-2 py-1.5 text-xs text-white focus:outline-none focus:border-blue-500/50" 
                    />
                 </div>
                 <div>
                    <span className="text-[10px] font-medium text-zinc-400 block mb-1">Description</span>
                    <textarea 
                      value={descValue} 
                      onChange={(e) => handleUpdate('description', e.target.value)}
                      placeholder="Details..."
                      rows={3}
                      className="w-full bg-black/30 border border-white/10 rounded px-2 py-1.5 text-xs text-white focus:outline-none focus:border-blue-500/50 resize-none" 
                    />
                 </div>
                 <SliderControl 
                    label="Label Distance" 
                    value={offsetValue} 
                    min="20" max="200" step="5"
                    onChange={(v: number) => handleUpdate('offset', v)} 
                 />
              </div>

              <div className="h-px bg-white/10 w-full" />

              {/* Transform Section */}
              <div className="flex flex-col gap-3">
                 <div className="flex items-center gap-2 mb-1">
                    <Move3d size={12} className="text-orange-400" />
                    <span className="text-[10px] font-bold uppercase tracking-wider text-zinc-400">Part Transform</span>
                 </div>

                 {/* Scale Control - Only visible when exploded */}
                 {isExploded ? (
                     <SliderControl 
                        label="Scale (Exploded)" 
                        value={meshScale} 
                        min="0.1" max="5.0" step="0.01"
                        displayValue={`${meshScale.toFixed(2)}x`}
                        onChange={updateScale} 
                     />
                 ) : (
                     <button 
                        onClick={toggleExploded}
                        className="w-full py-2 px-3 bg-zinc-900/50 border border-white/5 rounded text-center hover:bg-white/5 transition-colors flex items-center justify-center gap-2 group mb-2"
                     >
                        <Maximize2 size={12} className="text-orange-400 group-hover:scale-110 transition-transform"/>
                        <span className="text-[10px] text-zinc-400 group-hover:text-white">Enable <span className="text-orange-400 font-bold">Explode</span> to Scale</span>
                     </button>
                 )}

                 <div className="h-px bg-white/5 w-full my-1" />

                 <span className="text-[9px] font-bold uppercase tracking-wider text-zinc-500 mb-1">Exploded Position</span>
                 <SliderControl 
                    label="X Axis (Side)" 
                    value={ex} 
                    min={-2} max={2} step={0.01}
                    onChange={(v: number) => updateExplosion(0, v)} 
                 />
                 <SliderControl 
                    label="Y Axis (Up/Down)" 
                    value={ey} 
                    min={-2} max={2} step={0.01}
                    onChange={(v: number) => updateExplosion(1, v)} 
                 />
                 <SliderControl 
                    label="Z Axis (Fwd/Back)" 
                    value={ez} 
                    min={-2} max={2} step={0.01}
                    onChange={(v: number) => updateExplosion(2, v)} 
                 />
              </div>
          </div>
       </div>
  );
}

