    toggleWalking,
    isTurntableActive,
    setTurntableSpeed,
    turntableSpeed,
    toggleHelp,
    showHelp,
    isMobile,
    activeVideoStream,
    setVideoStream,
    addMaterial,
    setMaterial,
    selectedPart,
    partMaterials,
    materials
  } = useStore();

  const [activeTab, setActiveTab] = useState<'dashboard' | 'models' | 'materials' | 'colors' | 'mix' | 'light'>('dashboard');
  const [showWalkModal, setShowWalkModal] = useState(false);
  const [showLeftPanel, setShowLeftPanel] = useState(!isMobile);
  const [isCameraOverlayOpen, setIsCameraOverlayOpen] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  // --- Walk Modal Logic ---
  const handleWalkClick = () => {
    if (isWalking) {
      toggleWalking();
    } else {
      setShowWalkModal(true);
    }
  };

  const startWalking = (type: 'left' | 'right') => {
    setBaseShoeType(type);
    toggleWalking();
    setShowWalkModal(false);
  };

  // --- Camera Logic ---
  useEffect(() => {
    if (isCameraOverlayOpen && videoRef.current && streamRef.current) {
      videoRef.current.srcObject = streamRef.current;
      videoRef.current.play().catch(e => console.error("Error playing video preview:", e));
    }
  }, [isCameraOverlayOpen]);

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment', width: { ideal: 1080 }, aspectRatio: { ideal: 1 } } 
      });
      streamRef.current = stream;
      setIsCameraOverlayOpen(true);
    } catch (err) {
      console.error("Error accessing camera:", err);
      alert("Could not access camera. Please allow permissions.");
      setIsCameraOverlayOpen(false);
    }
  };

  const stopCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    setVideoStream(null);
    setIsCameraOverlayOpen(false);
  };

  const captureSnapshot = () => {
    if (videoRef.current) {
      const canvas = document.createElement('canvas');
      const size = Math.min(videoRef.current.videoWidth, videoRef.current.videoHeight);
      canvas.width = size;
      canvas.height = size;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        const startX = (videoRef.current.videoWidth - size) / 2;
        const startY = (videoRef.current.videoHeight - size) / 2;
        ctx.drawImage(videoRef.current, startX, startY, size, size, 0, 0, size, size);

        const dataUrl = canvas.toDataURL('image/jpeg');
        const newMat = {
          id: `cam-${Date.now()}`,
          name: `Snapshot ${new Date().toLocaleTimeString()}`,
          color: '#ffffff',
          roughness: 0.6,
          metalness: 0.0,
          type: 'fabric' as const,
          textureUrl: dataUrl
        };
        addMaterial(newMat);
        if (selectedPart) {
          setMaterial(selectedPart, newMat.id);
        }
      }
    }
    stopCamera();
  };

  const applyLiveTexture = () => {
    if (!streamRef.current || !selectedPart) return;
    setVideoStream(streamRef.current);
    const liveMatId = 'mat-live-video';
    const existing = materials.find(m => m.id === liveMatId);
    if (!existing) {
      const liveMat = {
        id: liveMatId,
        name: 'Live Camera Feed',
        color: '#ffffff',
        roughness: 0.5,
        metalness: 0.0,
        type: 'video' as const,
      };
      addMaterial(liveMat);
    }
    setMaterial(selectedPart, liveMatId);
    setIsCameraOverlayOpen(false);
  };

  const handleSaveRecording = () => {
    if (recordedUrl) {
      const a = document.createElement('a');
      a.href = recordedUrl;
      a.download = `nk-3d-turntable.webm`;
      a.click();
      discardRecording();
    }
  };

  return (
    <div className="absolute inset-0 pointer-events-none flex flex-col justify-between">

      {showWalkModal && (
        <div className="absolute inset-0 bg-black/60 z-[100] pointer-events-auto flex items-center justify-center backdrop-blur-sm p-4">
           <div className="bg-zinc-900 border border-white/10 rounded-2xl max-w-sm w-full shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
              <div className="p-4 border-b border-white/10 flex justify-between items-center bg-white/5">
                 <h3 className="text-white font-bold flex items-center gap-2">
                   <Footprints size={18} className="text-blue-500"/>
                   Walk Configuration
                 </h3>
                 <button onClick={() => setShowWalkModal(false)} className="text-white/50 hover:text-white">
                    <X size={18} />
                 </button>
              </div>
              <div className="p-6 flex flex-col gap-4 text-center">
                 <p className="text-sm text-zinc-400">
                   To animate correctly, please specify which shoe the uploaded 3D model represents.
                 </p>
                 <div className="grid grid-cols-2 gap-3">
                    <button 
                       onClick={() => startWalking('left')}
                       className="p-4 rounded-lg border border-white/10 hover:bg-white/5 hover:border-blue-500/50 transition-all flex flex-col items-center gap-2 group"
                    >
                       <div className="w-10 h-10 rounded-full bg-zinc-800 flex items-center justify-center text-zinc-400 group-hover:text-white font-bold text-lg">L</div>
                       <span className="text-sm font-medium text-zinc-300 group-hover:text-white">Left Shoe</span>
                    </button>

                    <button 
                       onClick={() => startWalking('right')}
                       className="p-4 rounded-lg border border-white/10 hover:bg-white/5 hover:border-blue-500/50 transition-all flex flex-col items-center gap-2 group"
                    >
                       <div className="w-10 h-10 rounded-full bg-zinc-800 flex items-center justify-center text-zinc-400 group-hover:text-white font-bold text-lg">R</div>
