                       ))}
                    </div>
                 </div>
                 <div className="space-y-2">
                    <div className="flex justify-between">
                       <span className="text-xs font-bold text-zinc-300 flex items-center gap-1.5">
                          <RotateCw size={12} className="text-zinc-500" />
