              </div>
           </div>
        </div>
      )}

      {recordingStatus === 'recording' && (
        <div className="absolute inset-0 bg-black/40 z-[100] pointer-events-auto flex flex-col items-center justify-center backdrop-blur-sm">
           <div className="bg-zinc-900 border border-red-500/50 rounded-2xl p-6 flex flex-col items-center gap-4 shadow-2xl">
              <Loader2 size={48} className="text-red-500 animate-spin" />
              <div className="text-center">
                <h3 className="text-white font-bold text-lg">Recording Turntable...</h3>
                <p className="text-zinc-400 text-sm mt-1">Rendering {turntableSettings.duration}s video at {turntableSettings.fps} FPS</p>
              </div>
              <button onClick={cancelRecording} className="mt-2 px-4 py-2 bg-zinc-800 hover:bg-zinc-700 text-white rounded-full text-xs border border-white/10">Press ESC to Cancel</button>
           </div>
        </div>
      )}

      {recordingStatus === 'review' && (
        <div className="absolute inset-0 bg-black/60 z-[100] pointer-events-auto flex items-center justify-center backdrop-blur-sm p-4">
          <div className="bg-zinc-900 border border-white/10 rounded-2xl max-w-sm w-full shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
             <div className="p-4 border-b border-white/10 flex justify-between items-center bg-white/5">
                <h3 className="text-white font-bold flex items-center gap-2"><Clapperboard size={18} className="text-blue-500"/>Recording Finished</h3>
             </div>
             <div className="p-6 text-center">
                {recordedUrl && <video src={recordedUrl} autoPlay loop muted className="w-full rounded-lg border border-white/10 mb-4 bg-black/50" />}
                <p className="text-zinc-300 text-sm mb-6">Your 360° turntable video is ready. Would you like to save it to your device?</p>
                <div className="flex gap-3">
                   <button onClick={discardRecording} className="flex-1 py-2.5 rounded-lg border border-white/10 text-zinc-400 hover:text-white hover:bg-white/5 transition-colors text-sm font-medium">Cancel</button>
                   <button onClick={handleSaveRecording} className="flex-1 py-2.5 rounded-lg bg-blue-600 hover:bg-blue-500 text-white shadow-lg shadow-blue-900/20 transition-colors text-sm font-medium flex items-center justify-center gap-2"><Download size={16} /> Save MP4</button>
                </div>
             </div>
          </div>
        </div>
      )}

      {isCameraOverlayOpen && (
        <div className="absolute inset-0 bg-black z-[90] pointer-events-auto flex flex-col items-center justify-center">
          <div className="flex justify-between items-center p-4 bg-black/50 absolute top-0 w-full z-10">
             <span className="text-white font-medium">Capture Texture (1:1)</span>
             <button onClick={stopCamera} className="text-white p-2"><X size={24} /></button>
          </div>

          {/* Square Viewport */}
          <div className="relative w-full max-md aspect-square bg-black overflow-hidden border-2 border-white/20 rounded-lg shadow-2xl mx-4">
             <video ref={videoRef} autoPlay playsInline className="absolute inset-0 w-full h-full object-cover" />

             {/* Grid Guide */}
             <div className="absolute inset-0 grid grid-cols-3 grid-rows-3 pointer-events-none opacity-30">
               <div className="border border-white/30"></div>
               <div className="border border-white/30"></div>
               <div className="border border-white/30"></div>
               <div className="border border-white/30"></div>
               <div className="border border-white/30"></div>
               <div className="border border-white/30"></div>
               <div className="border border-white/30"></div>
               <div className="border border-white/30"></div>
               <div className="border border-white/30"></div>
             </div>
          </div>

          <div className="absolute bottom-10 left-0 right-0 flex justify-center items-center gap-8 pb-8">
             <div className="flex flex-col items-center gap-2">
                <button onClick={captureSnapshot} className="w-16 h-16 rounded-full border-4 border-white flex items-center justify-center bg-white/20 active:bg-white/50 transition-colors"><div className="w-12 h-12 bg-white rounded-full" /></button>
                <span className="text-xs text-white font-medium shadow-black drop-shadow-md">Snapshot</span>
             </div>
             <div className="flex flex-col items-center gap-2">
                <button onClick={applyLiveTexture} disabled={!selectedPart} className={`w-16 h-16 rounded-full border-4 border-blue-500 flex items-center justify-center bg-blue-500/20 active:bg-blue-500/50 transition-colors ${!selectedPart ? 'opacity-50 cursor-not-allowed' : ''}`}><Video size={32} className="text-white" /></button>
                <span className="text-xs text-white font-medium shadow-black drop-shadow-md">Live Mode</span>
             </div>
          </div>
        </div>
      )}

      {showHelp && (
        <div className="absolute inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center pointer-events-auto p-4">
          <div className="bg-zinc-900 border border-white/10 rounded-2xl max-w-lg w-full shadow-2xl flex flex-col overflow-hidden">
            <div className="p-4 border-b border-white/10 flex justify-between items-center bg-white/5">
               <h3 className="text-white font-bold text-lg flex items-center gap-2"><HelpCircle size={20} className="text-blue-500"/>Asset Specifications</h3>
               <button onClick={toggleHelp} className="text-white/50 hover:text-white"><X size={20} /></button>
            </div>
            <div className="p-6 space-y-6 overflow-y-auto max-h-[70vh] custom-scrollbar">
               <div>
                 <h4 className="text-sm font-bold text-white mb-2">Supported File Formats</h4>
                 <div className="flex gap-2 mb-2">
                    <span className="px-2 py-1 bg-blue-500/20 text-blue-400 text-xs rounded border border-blue-500/30 font-mono">.GLB</span>
                    <span className="px-2 py-1 bg-blue-500/20 text-blue-400 text-xs rounded border border-blue-500/30 font-mono">.GLTF</span>
                    <span className="px-2 py-1 bg-orange-500/20 text-orange-400 text-xs rounded border-orange-500/30 font-mono">.OBJ</span>
                 </div>
                 <p className="text-xs text-zinc-400 leading-relaxed">
                    We recommend <strong>.GLB</strong> for best performance. <br/><br/>
                    If using <strong>.GLTF</strong> or <strong>.OBJ</strong>, please select <strong>ALL</strong> files (including .bin and textures) at once when uploading.
                 </p>
               </div>
            </div>
            <div className="p-4 bg-zinc-950 border-t border-white/10 text-center">
              <button onClick={toggleHelp} className="bg-white text-black px-6 py-2 rounded-full text-sm font-medium hover:bg-zinc-200 transition-colors">Got it</button>
            </div>
          </div>
        </div>
      )}

      {/* TOP TOOLBAR */}
      <TopToolbar 
        onWalkClick={handleWalkClick}
        onRecordingClick={openRecordingSettings}
        setShowLeftPanel={setShowLeftPanel}
        showLeftPanel={showLeftPanel}
      />

      <div className="flex-1 flex relative overflow-hidden pointer-events-none">

        {/* LEFT PANEL */}
        <LeftPanel showLeftPanel={showLeftPanel} />

        <div className="flex-1" />

        {/* RIGHT PANEL */}
        <RightPanel 
          activeTab={activeTab} 
          showLeftPanel={showLeftPanel}
          onStartCamera={startCamera}
          onStopCamera={stopCamera}
        />
      </div>

      <div className={`fixed bottom-6 left-0 right-0 flex justify-center z-[90] pointer-events-none transition-opacity ${recordingStatus === 'recording' ? 'opacity-0' : 'opacity-100'} ${isMobile ? 'bottom-0 bg-zinc-950/90 border-t border-white/5 py-3' : ''}`}>
        <div className={`${isMobile ? 'w-full flex justify-around pointer-events-auto' : 'bg-zinc-900/90 backdrop-blur-2xl border border-white/10 rounded-full p-2 flex gap-1 shadow-2xl pointer-events-auto'}`}>
           {[
             { id: 'dashboard', icon: LayoutDashboard, label: 'Dashboard' },
             { id: 'models', icon: Box, label: 'Models' },
             { id: 'materials', icon: Layers, label: 'Materials' },
             { id: 'colors', icon: Palette, label: 'Colors' },
             { id: 'mix', icon: Sparkles, label: 'AI Mix' },
             { id: 'light', icon: Sun, label: 'Light' },
           ].map((tab) => (
             <button
               key={tab.id}
               onClick={() => setActiveTab(tab.id as any)}
               className={`
                 relative rounded-full flex flex-col items-center justify-center gap-0.5 transition-all
                 ${isMobile ? 'w-auto h-auto p-2' : 'w-12 h-12'}
                 ${activeTab === tab.id ? (isMobile ? 'text-blue-500' : 'bg-blue-600 text-white shadow-lg shadow-blue-900/20 scale-110') : 'text-zinc-400 hover:text-white hover:bg-white/10'}
               `}
             >
               <tab.icon size={isMobile ? 24 : 20} strokeWidth={activeTab === tab.id ? 2.5 : 2} />
               {isMobile && <span className="text-[9px] font-medium">{tab.label}</span>}
             </button>
           ))}
        </div>
      </div>

    </div>
  );
};

// Sub-components
const LeftPanel = ({ showLeftPanel }: any) => {
  const isMobile = useStore(s => s.isMobile);
  const recordingStatus = useStore(s => s.recordingStatus);
  const displayParts = useStore(s => (s.currentModel || s.customParts.length > 0) ? s.customParts.map(id => ({ id, name: id })) : SHOE_PARTS);
  const selectedPart = useStore(s => s.selectedPart);
  const selectPart = useStore(s => s.selectPart);
  const showAnnotations = useStore(s => s.showAnnotations);

  if (!showLeftPanel) return null;

  return (
    <div className={`ml-6 md:ml-6 flex flex-row items-start gap-2 animate-in slide-in-from-left duration-500 absolute left-0 top-2 bottom-auto max-h-[calc(100%-1rem)] pointer-events-none z-20 transition-opacity ${recordingStatus === 'recording' ? 'opacity-0' : 'opacity-100'} ${isMobile ? 'top-[70px] ml-4 flex-col' : ''}`}>

        <div className={`w-48 bg-zinc-900/90 backdrop-blur-md rounded-xl border border-white/10 flex flex-col shadow-2xl overflow-hidden pointer-events-auto max-h-full shrink-0 ${isMobile ? 'bg-zinc-900/95 h-[30vh] w-64' : ''}`}>
          <div className="p-3 border-b border-white/5 bg-white/5 backdrop-blur-xl flex justify-between items-center shrink-0">
              <h3 className="text-xs font-bold uppercase tracking-wider text-zinc-400 flex items-center gap-2"><List size={14} /> Parts Layer</h3>
          </div>
          <div className="overflow-y-auto custom-scrollbar p-2 space-y-1 max-h-[400px] flex-1">
            {displayParts.map((part) => (
              <button
                key={part.id}
                onClick={() => selectPart(selectedPart === part.id ? null : part.id)}
                className={`w-full text-left px-3 py-2 rounded-lg text-xs font-medium transition-all flex items-center justify-between group ${selectedPart === part.id ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-zinc-400 hover:text-white hover:bg-white/10'}`}
              >
                <span className="truncate">{part.name}</span>
                {selectedPart === part.id && <CheckCircle size={12} className="text-white/80" />}
              </button>
            ))}
          </div>
        </div>

        {selectedPart && showAnnotations && (
            <div className={`w-56 bg-zinc-900/90 backdrop-blur-md rounded-xl border border-white/10 flex flex-col shadow-2xl overflow-hidden pointer-events-auto shrink-0 animate-in slide-in-from-left-2 duration-300 ${isMobile ? 'w-64 bg-zinc-900/95' : ''}`}>
                <PartProperties />
            </div>
        )}
    </div>
  );
};

const RightPanel = ({ activeTab, onStartCamera, onStopCamera }: any) => {
  const { 
    isMobile,
    recordingStatus,
    selectedPart,
    activeVideoStream,
    materials,
    partMaterials,
    uploadedAssets,
    currentModel,
    savedVariants,
    selectedVariantIds,
    isSelectionMode,
    isGenerating,
    environmentSettings,
    customEnvironment,
    currentLighting,
    showFloor,
    setMaterial,
    removeMaterial,
    addMaterial,
    removeAsset,
    setCurrentModel,
    loadVariant,
    deleteVariant,
    toggleVariantSelection,
    selectAllVariants,
    setSelectionMode,
    uploadAsset,
    uploadMaterial,
    uploadEnvironment,
    createPBRMaterial,
    generateFullDesign,
    setLighting,
    updateEnvironmentSettings,
    removeMaterialGroup
  } = useStore();

  const [showLibrary, setShowLibrary] = useState(false);
  const [prompt, setPrompt] = useState('');
  const [customHex, setCustomHex] = useState('#ffffff');
  const [expandedGroups, setExpandedGroups] = useState<Record<string, boolean>>({});

  const assetInputRef = useRef<HTMLInputElement>(null);
  const materialInputRef = useRef<HTMLInputElement>(null);
  const pbrInputRef = useRef<HTMLInputElement>(null);
  const environmentInputRef = useRef<HTMLInputElement>(null);

  const displayParts = (currentModel || useStore.getState().customParts.length > 0) ? useStore.getState().customParts.map(id => ({ id, name: id })) : SHOE_PARTS;

  const handleAssetUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    let mainFile: File | null = null;
    const resourceMap: Record<string, string> = {};

    Array.from(files).forEach((val) => {
      const file = val as File;
      const ext = file.name.split('.').pop()?.toLowerCase();
      if (ext === 'gltf' || ext === 'glb' || ext === 'obj') {
        mainFile = file;
      } else {
        resourceMap[file.name] = URL.createObjectURL(file);
      }
    });

    if (mainFile) {
       const url = URL.createObjectURL(mainFile);
       const extension = (mainFile as File).name.split('.').pop()?.toLowerCase() || 'glb';

       uploadAsset({
        id: `asset-${Date.now()}`,
        url,
        name: (mainFile as File).name,
        extension,
        resources: resourceMap
      });
    } else if (Object.keys(resourceMap).length > 0) {
       alert("Please include the main 3D model file (.gltf, .glb, or .obj) in your selection.");
    }
  };

  const handleMaterialUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) uploadMaterial(file);
  };

  const handleEnvironmentUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) uploadEnvironment(file);
  };

  const handlePBRUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) createPBRMaterial(file);
  };

  const handleGenerate = async () => {
    if (!prompt.trim()) return;
    await generateFullDesign(prompt);
    setExpandedGroups(prev => ({ ...prev, [prompt]: true }));
    setPrompt('');
  };

  const handleColorClick = (colorHex: string) => {
    if (!selectedPart) return;
    const currentMatId = partMaterials[selectedPart];
    const currentMat = materials.find(m => m.id === currentMatId);

    if (currentMat) {
       const newMat = {
          ...currentMat,
          id: `${currentMat.id}-tint-${colorHex.replace('#', '')}-${Date.now()}`,
          name: `${currentMat.name} (${colorHex})`,
          color: colorHex
       };
       addMaterial(newMat);
       setMaterial(selectedPart, newMat.id);
    } else {
       const newColorMat = {
          id: `color-${colorHex}-${Date.now()}`,
          name: `Color ${colorHex}`,
          color: colorHex,
          roughness: 0.5,
          metalness: 0.1,
          type: 'fabric' as const,
        };
        addMaterial(newColorMat);
        setMaterial(selectedPart, newColorMat.id);
    }
  };

  const handlePresetClick = (preset: typeof MATERIAL_PRESETS[0]) => {
    const newMat: Material = { 
      ...preset, 
      id: `custom-${preset.id}-${Date.now()}`,
      name: `${preset.name} (Custom)`
    };
    addMaterial(newMat);
    if(selectedPart) setMaterial(selectedPart, newMat.id);
  };

  const handleMaterialClick = (matId: string) => {
    if (selectedPart) setMaterial(selectedPart, matId);
  };

  const toggleGroup = (groupName: string) => {
    setExpandedGroups(prev => ({ ...prev, [groupName]: !prev[groupName] }));
  };

  const handleDeleteGroup = (e: React.MouseEvent, groupName: string) => {
     e.stopPropagation();
     removeMaterialGroup(groupName);
  };

  const aiMaterials = materials.filter(m => m.type === 'ai-generated');
  const aiGroups: Record<string, typeof aiMaterials> = {};
  aiMaterials.forEach(m => {
    const groupName = m.group || 'Older Generations';
    if (!aiGroups[groupName]) aiGroups[groupName] = [];
    aiGroups[groupName].push(m);
  });

  return (
    <div className={`
        flex flex-col gap-3 animate-in slide-in-from-right duration-500 absolute pointer-events-none z-20 transition-all
        ${recordingStatus === 'recording' ? 'opacity-0' : 'opacity-100'}
        ${isMobile 
           ? 'w-full bottom-[80px] left-0 right-0 px-2 slide-in-from-bottom-10' 
           : 'w-80 mr-6 right-0 top-2 bottom-auto max-h-[calc(100%-1rem)]'
        }
    `}>
       {/* Hidden Inputs */}
       <input type="file" multiple ref={assetInputRef} onChange={handleAssetUpload} accept=".glb,.gltf,.obj,.bin,.png,.jpg,.jpeg" className="hidden" />
       <input type="file" ref={materialInputRef} onChange={handleMaterialUpload} accept="image/*" className="hidden" />
       <input type="file" ref={pbrInputRef} onChange={handlePBRUpload} accept="image/*" className="hidden" />
       <input type="file" ref={environmentInputRef} onChange={handleEnvironmentUpload} accept=".hdr,.exr,.jpg,.jpeg,.png" className="hidden" />

       <div className={`bg-zinc-900/90 backdrop-blur-md border border-white/10 flex flex-col shadow-2xl overflow-hidden pointer-events-auto max-h-full shrink-0 transition-all duration-300 ${isMobile ? 'rounded-t-2xl border-b-0' : 'rounded-xl'}`}>
